import{_ as s,o as a,c as i,a2 as t}from"./chunks/framework.CHSDihme.js";const k=JSON.parse('{"title":"Contributing and Local Quality Gates","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/contributing.md","filePath":"en/guide/contributing.md","lastUpdated":1780308532000}'),n={name:"en/guide/contributing.md"};function l(o,e,r,h,p,d){return a(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="contributing-and-local-quality-gates" tabindex="-1">Contributing and Local Quality Gates <a class="header-anchor" href="#contributing-and-local-quality-gates" aria-label="Permalink to &quot;Contributing and Local Quality Gates&quot;">​</a></h1><p>This guide explains how to install, develop, test, and run the local quality gates before opening a PR. The goal is to help maintainers and contributors answer one question before review: did this change break the core Coding Agent workflow?</p><h2 id="setup" tabindex="-1">Setup <a class="header-anchor" href="#setup" aria-label="Permalink to &quot;Setup&quot;">​</a></h2><p>Install root dependencies with Bun:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span></code></pre></div><p>If your change touches <code>desktop/</code>, also install desktop dependencies:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> desktop</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span></code></pre></div><p>If your change touches <code>adapters/</code>, or if you run <code>check:adapters</code> / <code>check:native</code>, install adapter dependencies:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> adapters</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span></code></pre></div><p>Do not commit local artifacts such as <code>artifacts/quality-runs/</code>, <code>node_modules/</code>, or <code>desktop/node_modules/</code>.</p><h2 id="required-pr-gate" tabindex="-1">Required PR Gate <a class="header-anchor" href="#required-pr-gate" aria-label="Permalink to &quot;Required PR Gate&quot;">​</a></h2><p>Before opening a normal PR, contributors and AI coding agents should run the single entrypoint:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> verify</span></span></code></pre></div><p><code>bun run verify</code> is the one-command entrypoint and is equivalent to <code>bun run quality:pr</code>. This gate does not call real models, so every contributor can run it locally. It starts with an impact report, then actually runs the selected local gates for the changed paths: policy, desktop, server, adapters, native, docs, quarantine, and coverage. A non-zero exit means the branch is not ready for PR or push.</p><p>The main quality report embeds the current test scope, result matrix, coverage summary, and links to the full coverage/JUnit/log artifacts:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>artifacts/quality-runs/&lt;timestamp&gt;/report.md</span></span>
<span class="line"><span>artifacts/quality-runs/&lt;timestamp&gt;/report.json</span></span>
<span class="line"><span>artifacts/quality-runs/&lt;timestamp&gt;/junit.xml</span></span>
<span class="line"><span>artifacts/quality-runs/&lt;timestamp&gt;/logs/*.log</span></span>
<span class="line"><span>artifacts/coverage/&lt;timestamp&gt;/coverage-report.md</span></span>
<span class="line"><span>artifacts/coverage/&lt;timestamp&gt;/coverage-report.json</span></span></code></pre></div><p>Include the commands you ran and the report summary in your PR description. <code>quality:pr</code> / <code>quality:verify</code> remain available for contributors who prefer explicit quality command names, but docs and AI prompts should prefer <code>bun run verify</code>.</p><p>The coverage gate does four things: measures source-only coverage, enforces the baseline ratchet, reports target gaps against 75-80%+ maintained-area goals, and enforces changed-line coverage for new or modified executable production lines. The current baseline lives in <code>scripts/quality-gate/coverage-baseline.json</code>, and CI compares against the base branch baseline when available. New PRs must not lower coverage beyond the allowed window. Changes to <code>coverage-baseline.json</code> or <code>coverage-thresholds.json</code> require the maintainer-only <code>allow-coverage-baseline-change</code> label. Quarantine entries must keep an owner, reviewAfter date, and exit criteria; once reviewAfter expires, the default server and coverage gates fail until maintainers review the entry.</p><h2 id="ai-coding-agent-fix-loop" tabindex="-1">AI Coding Agent Fix Loop <a class="header-anchor" href="#ai-coding-agent-fix-loop" aria-label="Permalink to &quot;AI Coding Agent Fix Loop&quot;">​</a></h2><p>When asking an AI coding agent to work in this repo, use this as the acceptance instruction:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Run \`bun run verify\`. If it fails, read the latest</span></span>
<span class="line"><span>\`artifacts/quality-runs/&lt;timestamp&gt;/report.md\` and the relevant lane log,</span></span>
<span class="line"><span>fix the missing tests, coverage failures, type/lint/build errors, or docs/native</span></span>
<span class="line"><span>failures, then rerun \`bun run verify\` until it passes. Do not lower coverage</span></span>
<span class="line"><span>baselines or thresholds unless a maintainer explicitly requested it.</span></span></code></pre></div><p>Agents should handle failures in this order:</p><ol><li>Start with the Summary and Result Matrix in <code>artifacts/quality-runs/&lt;timestamp&gt;/report.md</code> to identify the failing lane.</li><li>If <code>Path-aware PR checks</code> failed, check for missing same-area tests, CLI core changes, or coverage policy changes. Do not bypass normal feature PRs with maintainer overrides.</li><li>If <code>Coverage gate</code> failed, open <code>artifacts/coverage/&lt;timestamp&gt;/coverage-report.md</code> or <code>coverage-report.json</code>, then fix <code>changedLines.failures</code> and <code>failures</code> first. <code>targetGaps</code> are technical-debt signals; touched areas should still improve.</li><li>If desktop/server/adapters/native/docs failed, read <code>artifacts/quality-runs/&lt;timestamp&gt;/logs/&lt;lane&gt;.log</code>, add tests or fix the build, then rerun the narrow command.</li><li>After narrow checks pass, run <code>bun run verify</code> again. The agent may only claim ready when the final Summary has <code>failed=0</code>.</li></ol><p>External reference points:</p><ul><li><a href="https://testing.googleblog.com/2020/08/code-coverage-best-practices.html" target="_blank" rel="noreferrer">Google Testing Blog</a>: 60% acceptable, 75% commendable, 90% exemplary; 90% is a reasonable lower threshold for changed/per-commit coverage.</li><li><a href="https://learn.microsoft.com/en-us/visualstudio/test/using-code-coverage-to-determine-how-much-code-is-being-tested" target="_blank" rel="noreferrer">Microsoft Visual Studio / Azure DevOps docs</a>: teams typically target about 80%, typical project requirements can be 75%, and generated code may be relaxed.</li><li><a href="https://chromium.googlesource.com/chromiumos/platform/ec/+/main/docs/code_coverage.md" target="_blank" rel="noreferrer">ChromiumOS EC</a>: new or changed lines require at least 80% coverage.</li></ul><h2 id="feature-quality-contract" tabindex="-1">Feature Quality Contract <a class="header-anchor" href="#feature-quality-contract" aria-label="Permalink to &quot;Feature Quality Contract&quot;">​</a></h2><p>Every feature, bugfix, and behavior change must ship with verifiable evidence. This rule applies to human authors and AI coding agents:</p><ul><li>Name the changed surface first: <code>desktop</code>, <code>server</code>, <code>adapter</code>, <code>native</code>, <code>docs</code>, <code>provider/runtime</code>, <code>agent-loop</code>, or <code>release</code>.</li><li>Production changes under <code>desktop/src</code>, <code>src/server</code>, <code>src/tools</code>, <code>src/utils</code>, or <code>adapters</code> must include same-area tests in the same PR unless a maintainer explicitly applies <code>allow-missing-tests</code>.</li><li>Pure logic needs unit tests. Server/API/provider/runtime behavior needs API or request-shape tests. Desktop UI/store/API behavior needs Vitest or Testing Library coverage. Cross-boundary user flows through UI, WebSocket, provider proxying, native sidecars, or release packaging need E2E or agent-browser smoke.</li><li>Agent loop, tool execution, provider routing, model selection, file editing, permissions, session resume, and desktop chat changes need mock/fixture tests in PR, plus live smoke or baseline evidence when provider access is available.</li><li>Coverage is part of the feature. This project follows a Google/Microsoft-style policy: generated/build output is not counted as product coverage, maintained product areas should move toward 75-80%+, and new or changed executable production lines must pass the changed-line coverage threshold in <code>coverage-thresholds.json</code>.</li><li>Do not lower <code>coverage-baseline.json</code> or <code>coverage-thresholds.json</code> just to pass the gate; real baseline/threshold changes require <code>allow-coverage-baseline-change</code> and a reason. Legacy low-coverage areas are debt; new PRs must leave touched areas better than they found them.</li><li>The PR description must record changed files, tests added, coverage report path, E2E/live report path or blocker, and remaining risk.</li></ul><h2 id="local-pre-push-gate" tabindex="-1">Local Pre-Push Gate <a class="header-anchor" href="#local-pre-push-gate" aria-label="Permalink to &quot;Local Pre-Push Gate&quot;">​</a></h2><p>Git hooks are local, so each clone needs to install the hook once:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hooks:install</span></span></code></pre></div><p>After installation, every <code>git push</code> runs the same verification entrypoint internally (<code>bun run quality:pr</code>, equivalent to <code>bun run verify</code>). If unit tests, coverage, docs/native/adapter checks, or any other selected path-aware lane fails, the local hook blocks the push.</p><p>Maintainers or contributors with model quota can also add real provider smoke and desktop agent-browser smoke to the pre-push hook:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> quality:providers</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hooks:install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --live-provider-model</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> minimax:main:minimax-main</span></span></code></pre></div><p>To run the full live baseline before every push, use:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hooks:install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --live-provider-model</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> minimax:main:minimax-main</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --live-mode</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> baseline</span></span></code></pre></div><p>These options are stored in local <code>.git/config</code> as <code>quality.prePush*</code> keys, so provider selectors and secrets are not committed. <code>smoke</code> mode covers real provider connectivity plus the desktop UI chat smoke; <code>baseline</code> mode also runs every real Coding Agent baseline case.</p><p>Maintainer-level overrides must also be explicit local config before the hook passes them to <code>quality:pr</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hooks:install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --allow-cli-core-change</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --allow-coverage-baseline-change</span></span></code></pre></div><p>This only affects the current clone and is not committed; PR CI still requires the matching labels.</p><h2 id="pr-ci-merge-gate" tabindex="-1">PR CI Merge Gate <a class="header-anchor" href="#pr-ci-merge-gate" aria-label="Permalink to &quot;PR CI Merge Gate&quot;">​</a></h2><p><code>.github/workflows/pr-quality.yml</code> runs for PR <code>opened</code>, <code>synchronize</code>, <code>reopened</code>, <code>ready_for_review</code>, <code>labeled</code>, and <code>unlabeled</code> events. It starts with <code>change-policy</code>, which maps changed files to the desktop, server, adapter, native, docs, and coverage lanes. The final <code>pr-quality-gate</code> job aggregates every selected job: failed selected jobs fail <code>pr-quality-gate</code>, while unselected jobs may be skipped.</p><p>Repository settings should protect <code>main</code> with GitHub branch protection / rulesets and require the <code>pr-quality-gate</code> status check. The local hook blocks low-quality pushes; the PR gate blocks low-quality merges.</p><h2 id="area-specific-checks" tabindex="-1">Area-Specific Checks <a class="header-anchor" href="#area-specific-checks" aria-label="Permalink to &quot;Area-Specific Checks&quot;">​</a></h2><p>Run the checks that match the files you changed:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> check:server</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      # Server API, WebSocket, providers, sessions, and related tests</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> check:desktop</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # Desktop lint, Vitest, and production build</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> check:adapters</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # IM adapter tests</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> check:native</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      # Desktop sidecars and Tauri native checks</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> check:docs</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # Docs build, using npm ci + docs:build</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> check:quarantine</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # Quarantine owners, exit criteria, and review windows</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> check:coverage</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # Root, desktop, and adapter coverage reports plus ratchet enforcement</span></span></code></pre></div><p>Focused tests are fine while developing, but run <code>bun run verify</code> before sending the PR.</p><p>Production code changes must include matching tests. Changes under <code>desktop/src/**</code>, <code>src/server/**</code>, <code>src/tools/**</code>, <code>src/utils/**</code>, or <code>adapters/**</code> without a same-area test file are blocked unless a maintainer applies <code>allow-missing-tests</code>. Coverage baseline/threshold changes are also blocked unless a maintainer applies <code>allow-coverage-baseline-change</code>.</p><h2 id="live-model-baseline" tabindex="-1">Live Model Baseline <a class="header-anchor" href="#live-model-baseline" aria-label="Permalink to &quot;Live Model Baseline&quot;">​</a></h2><p><code>quality:baseline</code> runs real Coding Agent tasks: it starts the local server, creates isolated fixtures, asks a model through chat to fix code, runs tests, and saves transcripts, diffs, verification logs, and a report. It also runs provider live smoke: saved or active OpenAI-compatible providers validate connectivity, proxy conversion, and streaming proxy behavior; env-only provider smoke validates upstream connectivity and the transform pipeline.</p><p>The default baseline command does not call real models:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> quality:baseline</span></span></code></pre></div><p>To actually call models, pass <code>--allow-live</code> and choose a local provider.</p><p>First list your local providers and copyable selectors:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> quality:providers</span></span></code></pre></div><p>Example output:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Saved providers:</span></span>
<span class="line"><span>  MiniMax</span></span>
<span class="line"><span>    selector: minimax</span></span>
<span class="line"><span>    main: MiniMax-M2.7-highspeed</span></span>
<span class="line"><span>      --provider-model minimax:main:minimax-main</span></span></code></pre></div><p>Copy one of the listed values:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> quality:gate</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --mode</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> baseline</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --allow-live</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --provider-model</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> minimax:main:minimax-main</span></span></code></pre></div><p>To run only provider smoke plus desktop agent-browser smoke, use:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> quality:smoke</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --provider-model</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> minimax:main:minimax-main</span></span></code></pre></div><p>You can run multiple models in one pass:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> quality:gate</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --mode</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> baseline</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --allow-live</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --provider-model</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> codingplan:main:codingplan-main</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --provider-model</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> minimax:main:minimax-main</span></span></code></pre></div><p>Provider selectors come from the providers saved in your local Desktop Settings &gt; Providers page. Contributors do not need the maintainer&#39;s provider UUIDs or vendor accounts. They can add their own provider locally, run <code>bun run quality:providers</code>, and choose their own model.</p><p>If you do not have a saved provider, you can run one unsaved provider smoke with environment variables:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">QUALITY_GATE_PROVIDER_BASE_URL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">https://example.com</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">QUALITY_GATE_PROVIDER_API_KEY=... </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">QUALITY_GATE_PROVIDER_MODEL=model-id </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">QUALITY_GATE_PROVIDER_API_FORMAT=openai_chat </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">bun </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> quality:gate</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --mode</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> baseline</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --allow-live</span></span></code></pre></div><h2 id="when-to-run-the-baseline" tabindex="-1">When To Run The Baseline <a class="header-anchor" href="#when-to-run-the-baseline" aria-label="Permalink to &quot;When To Run The Baseline&quot;">​</a></h2><p>Run the live baseline for changes touching:</p><ul><li>Desktop chat, session resume, WebSocket, or the CLI bridge</li><li>Provider, model, or runtime selection</li><li>Permissions, tool calls, file edits, and task execution</li><li>agent-browser smoke, Computer Use, Skills, or MCP</li><li>Release preparation or broad cross-module refactors</li></ul><p>If you do not have model access, still run <code>bun run verify</code> and state in the PR why the live baseline was not run.</p><h2 id="release-gate" tabindex="-1">Release Gate <a class="header-anchor" href="#release-gate" aria-label="Permalink to &quot;Release Gate&quot;">​</a></h2><p>Before a release, run release mode:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> quality:gate</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --mode</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> release</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --allow-live</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --provider-model</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">selecto</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">r</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">:main</span></span></code></pre></div><p>Release mode composes PR checks, baseline catalog validation, live baseline cases, provider smoke, desktop smoke, and native checks. Reports are written to <code>artifacts/quality-runs/&lt;timestamp&gt;/</code>. The hosted release workflow now runs <code>quality:gate --mode pr</code> as a non-live preflight before the packaging matrix and uploads a <code>release-quality-gate</code> artifact; maintainers still need to run the live release gate explicitly with an available provider.</p><p>In release mode, live lanes are not allowed to be silently skipped. Missing providers, model quota, or external account access will fail the gate and must be recorded as a release blocker.</p><h2 id="pr-workflow" tabindex="-1">PR Workflow <a class="header-anchor" href="#pr-workflow" aria-label="Permalink to &quot;PR Workflow&quot;">​</a></h2><ol><li>Create a product branch such as <code>fix/session-reconnect</code> or <code>feat/provider-quality-gate</code>.</li><li>Install dependencies and make the change.</li><li>Add tests for behavior changes.</li><li>Run focused checks for the affected area.</li><li>Optional but recommended: run <code>bun run hooks:install</code> so later pushes are blocked by failing gates.</li><li>Run <code>bun run verify</code>.</li><li>Run the live baseline for high-risk changes.</li><li>In the PR description, include user impact, verification commands, coverage/quality report summary, and known risks.</li></ol><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="can-i-run-checks-without-a-provider" tabindex="-1">Can I run checks without a provider? <a class="header-anchor" href="#can-i-run-checks-without-a-provider" aria-label="Permalink to &quot;Can I run checks without a provider?&quot;">​</a></h3><p>Yes. Run the normal PR gate:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> verify</span></span></code></pre></div><p>Only the live baseline needs a real model. Add your provider in Desktop Settings &gt; Providers, then run:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> quality:providers</span></span></code></pre></div><h3 id="what-if-provider-selectors-conflict" tabindex="-1">What if provider selectors conflict? <a class="header-anchor" href="#what-if-provider-selectors-conflict" aria-label="Permalink to &quot;What if provider selectors conflict?&quot;">​</a></h3><p>If two provider names produce the same selector, <code>quality:providers</code> falls back to the provider ID. Copy the <code>--provider-model ...</code> value it prints.</p><h3 id="what-if-a-model-id-contains-a-colon" tabindex="-1">What if a model ID contains a colon? <a class="header-anchor" href="#what-if-a-model-id-contains-a-colon" aria-label="Permalink to &quot;What if a model ID contains a colon?&quot;">​</a></h3><p>Prefer role selectors:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">--provider-model</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> custom:haiku:custom-haiku</span></span></code></pre></div><p>The runner resolves <code>haiku</code> to the real model ID from your local provider configuration.</p>`,89)])])}const u=s(n,[["render",l]]);export{k as __pageData,u as default};
